export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:08。燈亮回來。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有宣誓。沒有祈禱。沒有人站到前面做總結。沒有教主。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "家屬做的只是——", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "把影本重新放回不同顏色的資料夾。藍色是水瀨的。灰色是佐伯的。米色是藤川的。顏色不是暗號。是因為便宜文具店剛好只有這幾種。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "有人把沒吃完的飯糰塞進包裡。有人把保溫杯蓋旋緊。穿反光背心的父親把透明套裡的交通卡放回內袋。那個帶著孫子氣喘吸入器的祖母把吸入器檢查了一遍，確認藥量。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "角落有人在算錢。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是奉獻。是下次會議室的場地費。區民館三樓一小時八百日圓。他們在分。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "上次我出全額。這次三家庭分。藤川妳不用付，妳上次補了列印費。", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.FujikawaMari, character: "藤川真理", dialogue: "⋯⋯好。", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.FujikawaMari_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "有人在看手錶。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "末班公車。有人要趕。有人要先走，因為要去醫院換夜間看護班。她把圍巾繞了一圈，拎起裝著換洗衣物的塑膠袋，朝門口走。走的時候跟水瀨點了一下頭。沒有多說。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "另一個人在確認誰把離線筆電帶回去保管。輪到佐伯。他把筆電裝進一個舊電腦包，拉鏈拉了兩次才拉上。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這就是散場。沒有儀式。沒有誓詞。沒有人把手疊在一起。只有分房租。趕公車。帶飯糰。去醫院。確認誰保管筆電。這些普通到不能再普通的動作，把剛才那間半暗房間裡的所有邪教感全部拆掉了。", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他們不是教徒。他們是家人。是排班表。是醫院繳費單。是便利店飯糰。是沒有睡夠的臉。是把孩子的東西折好放回資料夾的人。", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把幾份不同研究說明單放在桌上。不是給澪的。是讓其他家屬確認下次要比對哪些文件。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有讓澪帶走任何一份。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從文件套裡抽出一張空白紙。遞給澪。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "這是比對模板。空白的。今晚妳只填妳弟弟手上的文件資料。", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪接過來。上面只有欄位名稱。沒有任何其他家庭的實際數值。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "計畫名稱。招募學校。聯絡電話末四碼。同意書版本。檢查日期。文件頁尾代碼。外部寄送／掃描日期。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "模板裡沒有其他家庭的值。那些資料留在會議室的文件套裡。不帶走。", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "明早七點半，清澄站前的家庭餐廳。先看妳填的欄位。九點區民館開門後，再比影本。只比文件，不談夢。", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯只比文件，不談夢。他把夢和文件分開。夢是情緒。文件是證據。他要的是證據。", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯七點半。家庭餐廳。九點區民館。十點——", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有說出十點。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯警方要求明天上午十時前回覆小鏡子原件的確認時段。佐伯不知道這件事。我沒有告訴他。七點半家庭餐廳。九點區民館。十點灣岸署。三個時間擠在同一個早上。", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我不能告訴他。如果我告訴他警方要扣押小鏡子，他可能會改變比對的順序。他可能會覺得我在用警方期限施壓。他可能會覺得我不只是來找弟弟的。我需要他的文件比對方法。我需要他在不知道警方期限的情況下，正常地跟我比文件。", background: Background.Chapter_11_Ch11_Act8_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把空白模板折好。放進外套內袋。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有告訴佐伯警方要求她翌日上午十時前回覆小鏡子原件的確認時段。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是她第二個沒有說出口的東西。第一個是千田的遺言。第二個是警方的倒數。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:20。會議室差不多空了。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃在門口等她。兩個人一起走進走廊。", background: Background.Chapter_11_Ch11_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊的日光燈嗡嗡響。牆上貼著書法班和育兒相談的海報。地板是老舊的塑膠磚。很普通。普通到讓人覺得剛才那間半暗房間裡發生的事不可能是真的。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃走在她旁邊。沒有說話。走了幾步。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "剛才那段，妳到底聽見了哪一句？", background: Background.Chapter_11_Ch11_Act8_S1, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是剛才那些錄音的總稱。是「那段」。是第三段。是水瀨葵的那段。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在問澪聽見了什麼。不是問所有人聽見的。是問澪一個人聽見的。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她知道我隱瞞了什麼。她不知道我隱瞞的是什麼。但她知道我在剛才那段錄音裡反應不對。她現在直接問。不繞。不試探。直接問。", background: Background.Chapter_11_Ch11_Act8_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我能說什麼。我能說東京嗎。不能。東京連著千田。千田連著兩輪。兩輪連著一切我不能交出去的東西。我能說第七天嗎。可以。第七天是錄音裡的。是大家都可能聽見的。是我的，也不只是我的。", background: Background.Chapter_11_Ch11_Act8_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "第七天。", background: Background.Chapter_11_Ch11_Act8_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三個字。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是真話。她確實聽見了「なのかめ」。她確實把其中一種可能理解為「第七天」。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這也是不完整的真話。她聽見的不只有第七天。她聽見了東京。她聽見了千田。她聽見了兩輪的死亡在同一個音節裡重疊。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她只給了水瀨佳乃三個字。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃沒有追問。她點了一下頭。很輕。像收下一件她不會退還、也不會拆開的東西。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個人走到區民館門口。水瀨佳乃往左。澪往右。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:30。澪回到門口那張桌角箱旁邊。憑編號取回自己的手機。撕開封口。螢幕亮起來。網路恢復。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩則先前已發出的通知跳出來。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一則。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.ShiraishiKotone, character: "琴音", dialogue: "醒了回我。我把吃的放冰箱。", background: Background.Chapter_11_Ch11_Act8_S1, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "18:05 發出的。三個多小時前。琴音不知道她在哪裡。琴音以為她在睡覺。琴音把吃的放進冰箱。等她醒。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯琴音。妳還在等我。妳不知道我今晚去了哪裡。妳不知道我剛才聽了什麼。妳不知道我現在手裡拿著一張空白模板和三個不能說出口的東西。妳只知道我還沒回妳。妳把吃的放冰箱。等我醒。", background: Background.Chapter_11_Ch11_Act8_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二則。來自灣岸署。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "關於上次筆錄提到的小鏡子，請在明天上午十點前回覆方便帶原件到警署確認的時間。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "上午十時。明天。距離現在不到十二個小時。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯七點半家庭餐廳。九點區民館。十點灣岸署。小鏡子原件還在我上鎖的抽屜裡。如果我十點前帶去署內，它可能被暫時保管。可能被扣押。可能再也拿不回來。在它離開我手上之前，我必須完成所有我能完成的記錄。", background: Background.Chapter_11_Ch11_Act8_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她低頭看著佐伯給她的那張空白模板。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "計畫名稱。招募學校。聯絡電話末四碼。同意書版本。檢查日期。文件頁尾代碼。外部寄送／掃描日期。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "七個欄位。七個空格。等她今晚填入悠真的資料。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯千田說過東京。一個在他死前數十日便留下錄音的孩子，也可能說過相同的音節。兩條不同的資料鏈。一條是瀕死工程師的遺言。一條是失蹤少女的夢話。它們是否共享同一個隱藏的來源，我不知道。", background: Background.Chapter_11_Ch11_Act8_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我只知道一件事。千田不是唯一一個說出這個詞的人。在他死之前，已經有一個孩子的夢裡裝著同樣的聲音。", background: Background.Chapter_11_Ch11_Act8_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:45。區民館的門在她身後關上。走廊的日光燈滅了一排。夜風從停車場那邊過來。涼的。帶著一點遠處的水氣。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手機放進口袋。空白模板折在外套內袋裡。三個不能說出口的東西壓在胸口。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走向公車站。", background: Background.Chapter_11_Ch11_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她還不知道孩子口中的東京是什麼。她只知道，那不是千田一個人的瘋話。", background: Background.Chapter_11_Ch11_Act8_S1 },
];
